package main

import (
    "database/sql"
    "fmt"
    "log"

    _ "github.com/mattn/go-sqlite3"
)

// ---- SQL operations ----
func main() {
    fmt.Println("=== Working with SQL ===")

    // ---- Open database ----
    db, err := sql.Open("sqlite3", "./data.db")
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    // ---- Create table ----
    createTableSQL := `
    CREATE TABLE IF NOT EXISTS players (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        health INTEGER DEFAULT 100,
        attack INTEGER DEFAULT 10,
        level INTEGER DEFAULT 1
    );
    `

    _, err = db.Exec(createTableSQL)
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("Table created")

    // ---- Insert data ----
    insertSQL := `INSERT INTO players (name, health, attack, level) VALUES (?, ?, ?, ?)`

    result, err := db.Exec(insertSQL, "Hero", 100, 20, 5)
    if err != nil {
        log.Fatal(err)
    }

    id, _ := result.LastInsertId()
    fmt.Printf("Inserted player with ID: %d\n", id)

    _, err = db.Exec(insertSQL, "Aragorn", 120, 25, 8)
    if err != nil {
        log.Fatal(err)
    }

    // ---- Query single row ----
    var player struct {
        ID     int
        Name   string
        Health int
        Attack int
        Level  int
    }

    row := db.QueryRow("SELECT id, name, health, attack, level FROM players WHERE id = ?", 1)
    err = row.Scan(&player.ID, &player.Name, &player.Health, &player.Attack, &player.Level)
    if err != nil {
        log.Fatal(err)
    }

    fmt.Printf("Player: ID=%d, Name=%s, Health=%d, Attack=%d, Level=%d\n",
        player.ID, player.Name, player.Health, player.Attack, player.Level)

    // ---- Query multiple rows ----
    fmt.Println("\nAll players:")

    rows, err := db.Query("SELECT id, name, health, attack, level FROM players")
    if err != nil {
        log.Fatal(err)
    }
    defer rows.Close()

    for rows.Next() {
        var p struct {
            ID     int
            Name   string
            Health int
            Attack int
            Level  int
        }
        err = rows.Scan(&p.ID, &p.Name, &p.Health, &p.Attack, &p.Level)
        if err != nil {
            log.Fatal(err)
        }
        fmt.Printf("  %d: %s (HP: %d, ATK: %d, Lv: %d)\n",
            p.ID, p.Name, p.Health, p.Attack, p.Level)
    }

    // ---- Update data ----
    updateSQL := `UPDATE players SET health = ? WHERE id = ?`
    _, err = db.Exec(updateSQL, 150, 1)
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("\nUpdated player 1 health to 150")

    // ---- Delete data ----
    deleteSQL := `DELETE FROM players WHERE id = ?`
    _, err = db.Exec(deleteSQL, 2)
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("Deleted player 2")

    // ---- Query after delete ----
    fmt.Println("\nAfter delete:")
    rows2, err := db.Query("SELECT id, name, health FROM players")
    if err != nil {
        log.Fatal(err)
    }
    defer rows2.Close()

    for rows2.Next() {
        var id int
        var name string
        var health int
        rows2.Scan(&id, &name, &health)
        fmt.Printf("  %d: %s (HP: %d)\n", id, name, health)
    }
}

