package main

import (
    "database/sql"
    "fmt"
    "log"

    _ "github.com/mattn/go-sqlite3"
)

func main() {
    db, err := sql.Open("sqlite3", "./users.db")
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    _, err = db.Exec(`CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        age INTEGER
    )`)
    if err != nil {
        log.Fatal(err)
    }

    _, err = db.Exec("INSERT INTO users (name, age) VALUES (?, ?)", "Alice", 25)
    if err != nil {
        log.Fatal(err)
    }

    rows, err := db.Query("SELECT id, name, age FROM users")
    if err != nil {
        log.Fatal(err)
    }
    defer rows.Close()

    fmt.Println("Users:")
    for rows.Next() {
        var id int
        var name string
        var age int
        rows.Scan(&id, &name, &age)
        fmt.Printf("  %d: %s (age %d)\n", id, name, age)
    }

    _, err = db.Exec("UPDATE users SET age = 26 WHERE name = ?", "Alice")
    if err != nil {
        log.Fatal(err)
    }

    _, err = db.Exec("DELETE FROM users WHERE name = ?", "Alice")
    if err != nil {
        log.Fatal(err)
    }

    fmt.Println("User deleted")
}
